import React, { useState, useEffect } from "react";
import { AppBar, Toolbar, IconButton, Typography, Button, Drawer, List, ListItem, ListItemText, useMediaQuery, Box, Menu, MenuItem } from "@mui/material";
import { ThemeProvider, createTheme } from "@mui/material/styles";
import DarkModeIcon from "@mui/icons-material/DarkModeRounded";
import LightModeIcon from "@mui/icons-material/LightModeRounded";
import Brightness4Icon from "@mui/icons-material/Brightness4";

const sections = [
  { title: "About", url: "#about" },
  { title: "Skills", url: "#skills" },
  { title: "Experience", url: "#experience" },
  { title: "Projects", url: "#projects" },
  { title: "Education", url: "#education" },
  { title: "Contact", url: "#contact" }
];

const Dashboard = () => {
  const prefersDarkMode = window.matchMedia("(prefers-color-scheme: dark)").matches;

  const getSavedTheme = () => localStorage.getItem("theme") || "system";
  const [mode, setMode] = useState(getSavedTheme);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [anchorEl, setAnchorEl] = useState(null);

  // Function to apply theme
  const setTheme = (theme) => {
    if (theme === "light" || theme === "dark") {
      document.documentElement.setAttribute("data-theme", theme);
      localStorage.setItem("theme", theme);
    } else if (theme === "system") {
      document.documentElement.removeAttribute("data-theme");
      localStorage.setItem("theme", "system");
    }
    setMode(theme);
  };

  // Apply theme from storage or system preference
  useEffect(() => {
    const savedTheme = getSavedTheme();
    if (savedTheme === "system") {
      setTheme(prefersDarkMode ? "dark" : "light");
    } else {
      setTheme(savedTheme);
    }

    // Listen for system theme changes
    const handleSystemThemeChange = (e) => {
      if (localStorage.getItem("theme") === "system") {
        setTheme(e.matches ? "dark" : "light");
      }
    };

    const mediaQuery = window.matchMedia("(prefers-color-scheme: dark)");
    mediaQuery.addEventListener("change", handleSystemThemeChange);

    return () => {
      mediaQuery.removeEventListener("change", handleSystemThemeChange);
    };
  }, [prefersDarkMode]);

  // Create theme dynamically
  const selectedTheme = createTheme({
    palette: {
      mode: mode === "system" ? (prefersDarkMode ? "dark" : "light") : mode,
    },
  });

  // Toggle Menu
  const handleMenuClick = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  return (
    <ThemeProvider theme={selectedTheme}>
      <AppBar position="fixed" sx={{ width: "100%", zIndex: 1201, background: "transparent", borderBottom: "1px solid var(--border)" }}>
        <Toolbar sx={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          {/* Portfolio Title */}
          <Typography variant="h6">My Portfolio</Typography>

          {/* Theme Toggle */}
          <IconButton color="inherit" onClick={handleMenuClick}>
            {mode === "dark" ? <DarkModeIcon /> : mode === "light" ? <LightModeIcon /> : <Brightness4Icon />}
          </IconButton>
          <Menu anchorEl={anchorEl} open={Boolean(anchorEl)} onClose={handleMenuClose}>
            <MenuItem onClick={() => { setTheme("light"); handleMenuClose(); }}>
              <LightModeIcon sx={{ marginRight: 1 }} />
              Light
            </MenuItem>
            <MenuItem onClick={() => { setTheme("dark"); handleMenuClose(); }}>
              <DarkModeIcon sx={{ marginRight: 1 }} />
              Dark
            </MenuItem>
            <MenuItem onClick={() => { setTheme("system"); handleMenuClose(); }}>
              <Brightness4Icon sx={{ marginRight: 1 }} />
              System
            </MenuItem>
          </Menu>
        </Toolbar>
      </AppBar>

      {/* Drawer for Mobile */}
      <Drawer anchor="left" open={drawerOpen} onClose={() => setDrawerOpen(false)}>
        <Box sx={{ width: 250, padding: 2 }}>
          <Typography variant="h6">My Portfolio</Typography>
          <List>
            {sections.map((section) => (
              <ListItem button key={section.title} onClick={() => setDrawerOpen(false)} component="a" href={section.url}>
                <ListItemText primary={section.title} />
              </ListItem>
            ))}
          </List>
        </Box>
      </Drawer>

      {/* Content below navbar */}
      <Box sx={{ marginTop: "84px", padding: 4 }}>
        <Typography variant="h4">Welcome to My Portfolio</Typography>
      </Box>
    </ThemeProvider>
  );
};

export default Dashboard;
